#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int X; scanf("%d", &X);
        if (X >= 111 && X <= 888) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

